def compute_trend(time_steps):
    first = time_steps[-6]["glucose"]
    last = time_steps[-1]["glucose"]
    diff = last - first

    if diff > 15:
        return "rapidly rising"
    elif diff > 5:
        return "rising"
    elif diff < -15:
        return "rapidly falling"
    elif diff < -5:
        return "falling"
    else:
        return "stable"


def compute_recent_change(time_steps):
    first = time_steps[-6]["glucose"]
    last = time_steps[-1]["glucose"]
    diff = last - first
    return f"{'+' if diff >= 0 else ''}{diff} mg/dL in last 30 minutes"

